        'services.tag': '// DIVISIONS',
        'services.heading': 'Strategic Implementations',
        'services.desc': 'Resilient solutions engineered strictly countering contemporary aggressive structural compromises ranging natively from discovery mechanisms to ultimate remediation execution.',
        'card.redteam.title': 'Red Team / Pentest',
        'card.redteam.desc': 'Aggressive adversarial simulation exposing deeply rooted structural weaknesses actively bypassing conventional systematic perimeter evaluations entirely.',
        'card.redteam.li1': 'Web & Mobile Intrusions',
