        'card.blueteam.title': 'Blue Team Überwacher',
        'card.blueteam.desc': 'Ihre absolut niemals ruhende 24/7 Abwehrzentrale. Algorithmen der Feinde verglühen reaktionslos im Firewall-Schmelzofen unseres wachsamen Krisenstabs.',
        'card.blueteam.li1': '24/7 SIEM-Prozess-Registrierung',
        'card.blueteam.li2': 'Verdeckte Code-Inquisition',
        'card.blueteam.li3': 'Vollständige Krisen-Auslöschung',
